List<int> mergeSorted(List<int> list1, List<int> list2) {
  List<int> result = [];
  int i = 0, j = 0;

  while (i < list1.length && j < list2.length) {
    if (list1[i] <= list2[j]) {
      result.add(list1[i]);
      i++;
    } else {
      result.add(list2[j]);
      j++;
    }
  }

  // Add remaining elements
  while (i < list1.length) {
    result.add(list1[i]);
    i++;
  }
  while (j < list2.length) {
    result.add(list2[j]);
    j++;
  }

  return result;
}

// Usage
print(mergeSorted([1, 3, 5], [2, 4, 6])); // [1, 2, 3, 4, 5, 6]
